import sys
from heapq import heappop, heappush

def solve(data: str) -> str:
    tokens = iter(map(int, data.split()))
    n, m = next(tokens), next(tokens)
    graph = [[] for _ in range(n)]
    for _ in range(m):
        source, target, cost = next(tokens), next(tokens), next(tokens)
        graph[source].append((target, cost))
    heuristic = [next(tokens) for _ in range(n)]
    start, goal = next(tokens), next(tokens)
    best = {start: 0}
    frontier = [(heuristic[start], 0, start)]
    while frontier:
        _, cost, node = heappop(frontier)
        if cost != best.get(node):
            continue
        if node == goal:
            return str(cost)
        for neighbor, edge in graph[node]:
            candidate = cost + edge
            if candidate < best.get(neighbor, 10**18):
                best[neighbor] = candidate
                heappush(frontier, (candidate + heuristic[neighbor], candidate, neighbor))
    return 'unreachable'

if __name__ == "__main__":
    print(solve(sys.stdin.read()), end="")
